def use_supabase_state() -> bool:
    return os.environ.get("CLEANRUN_STATE_BACKEND", "local").lower() == "supabase"


@lru_cache
def get_supabase_client():
    from supabase import create_client

    url = os.environ.get("SUPABASE_URL")
    key = os.environ.get("SUPABASE_SERVICE_ROLE_KEY") or os.environ.get("SUPABASE_KEY")

    if not url:
        raise RuntimeError("Missing SUPABASE_URL")

    if not key:
        raise RuntimeError("Missing SUPABASE_SERVICE_ROLE_KEY or SUPABASE_KEY")

    return create_client(url, key)


def validate_state(state: dict[str, Any]) -> dict[str, Any]:
    if (
        not isinstance(state, dict)
        or state.get("version") != STATE_VERSION
        or not all(key in state for key in ("items", "settings", "plans"))
    ):
        raise ValueError("incomplete state")

    for item in state["items"]:
        item.setdefault("originalPhotoMeta", [])

    state.setdefault("settings", {}).setdefault("theme", "light")
    return state


def save_state(state: dict[str, Any]) -> None:
    """Persist CleanRun state to Supabase when enabled, otherwise local JSON."""
    with LOCK:
        if use_supabase_state():
            table = os.environ.get("CLEANRUN_STATE_TABLE", "cleanrun_state")
            state_id = os.environ.get("CLEANRUN_STATE_ID", "production")

            get_supabase_client().table(table).upsert(
                {
                    "id": state_id,
                    "payload": state,
                    "updated_at": now_iso(),
                },
                on_conflict="id",
            ).execute()
            return

        DATA_FILE.parent.mkdir(parents=True, exist_ok=True)
        fd, name = tempfile.mkstemp(
            prefix="cleanrun-",
            suffix=".json",
            dir=DATA_FILE.parent,
        )

        try:
            with os.fdopen(fd, "w", encoding="utf-8") as stream:
                json.dump(state, stream, ensure_ascii=False, indent=2)
            os.replace(name, DATA_FILE)
        finally:
            if os.path.exists(name):
                os.unlink(name)


def load_state() -> dict[str, Any]:
    with LOCK:
        if use_supabase_state():
            table = os.environ.get("CLEANRUN_STATE_TABLE", "cleanrun_state")
            state_id = os.environ.get("CLEANRUN_STATE_ID", "production")

            response = (
                get_supabase_client()
                .table(table)
                .select("payload")
                .eq("id", state_id)
                .limit(1)
                .execute()
            )

            rows = response.data or []

            if rows:
                return validate_state(rows[0]["payload"])

            state = default_state()
            save_state(state)
            return state

        try:
            with DATA_FILE.open(encoding="utf-8") as stream:
                state = json.load(stream)

            return validate_state(state)

        except (OSError, ValueError, json.JSONDecodeError):
            state = default_state()
            save_state(state)
            return state

STATE = load_state()


def use_supabase_storage() -> bool:
    return os.environ.get("CLEANRUN_STORAGE", "local").lower() == "supabase"


def _photo_looks_like_uploadable_base64(value: str) -> bool:
    if not isinstance(value, str) or not value.strip():
        return False

    value = value.strip()

    if value.startswith("data:image/"):
        return True

    if value.startswith("http://") or value.startswith("https://") or value.startswith("seed://"):
        return False

    return value.startswith(("/9j/", "9j/", "iVBOR", "UklGR"))


def _data_url_mime(value: str) -> str | None:
    if not isinstance(value, str) or not value.startswith("data:") or "," not in value:
        return None
    return value.split(",", 1)[0].split(";")[0].replace("data:", "") or None


def _split_photo_base64(photo: str) -> tuple[str, str]:
    value = photo.strip()

    if value.startswith("data:"):
        header, encoded = value.split(",", 1)
        mime_type = header.split(";")[0].replace("data:", "") or "image/jpeg"
        return mime_type, encoded

    if value.startswith("iVBOR"):
        return "image/png", value

    if value.startswith("UklGR"):
        return "image/webp", value

    return "image/jpeg", value


def upload_data_url_asset_to_supabase(data_url: str, folder: str, max_bytes: int | None = None) -> str:
    """Upload a browser data URL to Supabase Storage and return its public URL."""
    if not isinstance(data_url, str) or not data_url.startswith("data:") or "," not in data_url:
        return data_url

    if not use_supabase_storage():
        return data_url

    header, encoded = data_url.split(",", 1)
    mime_type = header.split(";")[0].replace("data:", "") or "application/octet-stream"
    extension = mimetypes.guess_extension(mime_type) or ".bin"
    if extension == ".jpe":
        extension = ".jpg"

    try:
        raw_bytes = base64.b64decode(re.sub(r"\s+", "", encoded), validate=True)
    except (binascii.Error, ValueError) as exc:
        raise ValueError("invalid file payload") from exc

    if max_bytes is None:
        max_bytes = int(os.environ.get("CLEANRUN_MAX_FILE_BYTES", "50000000"))
    if len(raw_bytes) > max_bytes:
        raise ValueError("uploaded file is too large")

    bucket = os.environ.get("CLEANRUN_STORAGE_BUCKET", "cleanrun-evidence")
    now_path = datetime.now(timezone.utc).strftime("%Y/%m/%d")
    file_path = f"{folder}/{now_path}/{uuid.uuid4().hex}{extension}"

    try:
        client = get_supabase_client()
        client.storage.from_(bucket).upload(
            path=file_path,
            file=raw_bytes,
            file_options={
                "content-type": mime_type,
                "upsert": "false",
            },
        )
        return client.storage.from_(bucket).get_public_url(file_path)
    except Exception as exc:
        raise RuntimeError(f"Supabase file upload failed: {exc}") from exc


def upload_data_url_to_supabase(data_url: str, folder: str = "evidence") -> str:
    if not _photo_looks_like_uploadable_base64(data_url):
        return data_url

    if not use_supabase_storage():
        return data_url

    mime_type, encoded = _split_photo_base64(data_url)
    extension = mimetypes.guess_extension(mime_type) or ".jpg"
    if extension == ".jpe":
        extension = ".jpg"

    try:
        raw_bytes = base64.b64decode(re.sub(r"\s+", "", encoded), validate=True)
    except (binascii.Error, ValueError) as exc:
        raise ValueError("invalid image payload") from exc

    max_bytes = int(os.environ.get("CLEANRUN_MAX_IMAGE_BYTES", "8000000"))
    if len(raw_bytes) > max_bytes:
        raise ValueError("uploaded image is too large")

    bucket = os.environ.get("CLEANRUN_STORAGE_BUCKET", "cleanrun-evidence")
    now_path = datetime.now(timezone.utc).strftime("%Y/%m/%d")
    file_path = f"{folder}/{now_path}/{uuid.uuid4().hex}{extension}"

    try:
        client = get_supabase_client()
        client.storage.from_(bucket).upload(
            path=file_path,
            file=raw_bytes,
            file_options={
                "content-type": mime_type,
                "upsert": "false",
            },
        )
        return client.storage.from_(bucket).get_public_url(file_path)
    except Exception as exc:
        raise RuntimeError(f"Supabase photo upload failed: {exc}") from exc


def maybe_upload_photo(photo: Any, folder: str = "evidence") -> Any:
    if not photo or not isinstance(photo, str):
        return photo

    if not _photo_looks_like_uploadable_base64(photo):
        return photo

    return upload_data_url_to_supabase(photo, folder=folder)


def upload_photo_list(photos: Any, folder: str = "evidence") -> list[Any]:
    if not photos:
        return []

    if not isinstance(photos, list):
        return []

    return [maybe_upload_photo(photo, folder=folder) for photo in photos]


def maybe_upload_plan_asset(value: Any, folder: str = "plans") -> Any:
    if not isinstance(value, str):
        return value

    mime_type = _data_url_mime(value)
    if mime_type not in {"application/pdf", "image/jpeg", "image/png", "image/webp", "image/gif"}:
        return value

    return upload_data_url_asset_to_supabase(value, folder=folder)

def get_item(item_id: str) -> dict[str, Any]:
    for item in STATE["items"]:
        if item["id"] == item_id:
            return item
    raise KeyError("Item not found")


def audit(item: dict[str, Any], action: str, by: str | None = None, note: str | None = None) -> None:
    at = now_iso()
    event = {"at": at, "action": action}
    if by:
        event["by"] = by
    if note:
        event["note"] = note
    item.setdefault("auditEvents", []).append(event)
    item["updatedAt"] = at
    item["sync"] = "synced"


def next_code(kind: str) -> str:
    prefix = CODE_PREFIX[kind]
    nums = []
    for item in STATE["items"]:
        match = re.fullmatch(rf"{prefix}-(\d+)", item.get("code", ""))
        if match:
            nums.append(int(match.group(1)))
    return f"{prefix}-{max(nums, default=0) + 1:03d}"


