def parse_transcript(transcript: str) -> dict[str, Any]:
    """Rule-for-rule Python equivalent of the original offline voice parser."""
    original, text = transcript.strip(), transcript.strip().lower()
    if not text:
        return {}
    result: dict[str, Any] = {"priority": "high", "description": original}
    client_words = ["client", "superintendent", "consultant", "architect", "buyer", "owner raised", "client raised"]
    incomplete_words = ["not finished", "unfinished", "incomplete", "missing", "not installed", "pending", "not yet", "outstanding work", "not complete", "yet to"]
    defect_words = ["damaged", "defective", "cracked", "crack", "scratched", "broken", "chipped", "leak", "stain", "drummy", "lippage", "faulty"]
    if any(word in text for word in client_words): result["type"] = "client"
    elif any(word in text for word in incomplete_words): result["type"] = "incomplete"
    elif any(word in text for word in defect_words): result["type"] = "defect"
    numbers = {"ground": 0, "one": 1, "two": 2, "three": 3, "four": 4, "five": 5,
               "six": 6, "seven": 7, "eight": 8, "nine": 9, "ten": 10,
               "eleven": 11, "twelve": 12}
    match = re.search(r"\b(block|tower|building)\s+([a-z0-9]+)", text)
    if match:
        value = numbers.get(match.group(2), match.group(2).upper())
        result["building"] = f"{match.group(1).title()} {value}"
    match = re.search(r"\b(?:level|floor|l)\s*([0-9]{1,2})", text)
    if match: result["level"] = f"L{int(match.group(1)):02d}"
    else:
        match = re.search(r"\b(?:level|floor)\s+(ground|one|two|three|four|five|six|seven|eight|nine|ten|eleven|twelve)", text)
        if match: result["level"] = f"L{numbers[match.group(1)]:02d}"
    match = re.search(r"\b(?:unit|apartment|apt|lot)\s+([a-z0-9-]+)", text)
    if match: result["unit"] = match.group(1).upper()
    for room in ROOMS:
        if room in text:
            bed = re.search(r"bedroom\s*([0-9])", text)
            result["room"] = f"Bedroom {bed.group(1)}" if room == "bedroom" and bed else room.title()
            break
    for trade, hints in TRADE_HINTS.items():
        if any(hint in text for hint in hints):
            result["trade"] = trade
            break
    for sub in STATE["settings"]["subcontractors"]:
        tokens = [token for token in sub.lower().split() if len(token) > 3]
        if sub.lower() in text or any(token in text for token in tokens):
            result["subcontractor"] = sub
            break
    if any(word in text for word in ["urgent", "critical", "immediate", "safety", "stop work", "asap", "emergency"]):
        result["priority"] = "urgent"
    if "today" in text: result["dueDate"] = day_iso()
    elif "tomorrow" in text: result["dueDate"] = day_iso(1)
    elif "end of week" in text or "eow" in text:
        result["dueDate"] = day_iso((4 - date.today().weekday()) % 7 or 7)
    else:
        match = re.search(r"\bin\s+([0-9]{1,2})\s+days?", text)
        if match: result["dueDate"] = day_iso(int(match.group(1)))
        else:
            weekdays = ["monday", "tuesday", "wednesday", "thursday", "friday", "saturday", "sunday"]
            for index, weekday in enumerate(weekdays):
                if weekday in text:
                    result["dueDate"] = day_iso((index - date.today().weekday()) % 7 or 7)
                    break
    if result.get("type") == "client":
        for needle, label in [("superintendent", "Superintendent"), ("consultant", "Consultant"), ("architect", "Architect"), ("buyer", "Buyer"), ("client", "Client PM")]:
            if needle in text:
                result["raisedBy"] = label
                break
    sentence = re.split(r"[.!?]", original, maxsplit=1)[0].strip()
    result["title"] = sentence if len(sentence) <= 60 else sentence[:57].rstrip() + "…"
    return result


def create_item(payload: dict[str, Any]) -> dict[str, Any]:
    payload = copy.deepcopy(payload)

    required = ("type", "project", "description", "dueDate")
    if any(not payload.get(field) for field in required):
        raise ValueError("type, project, description and dueDate are required")
    if payload["type"] not in CODE_PREFIX:
        raise ValueError("invalid item type")
    if payload["type"] in {"defect", "client"} and not payload.get("originalPhotos"):
        raise ValueError("defects and client defects require at least one original photo")

    item_id = payload.get("id") or new_id()
    payload["originalPhotos"] = upload_photo_list(
        payload.get("originalPhotos", []),
        folder=f"items/{item_id}/original",
    )

    at = now_iso()
    code = next_code(payload["type"])
    item = {
        "id": item_id, "code": code, "status": payload.get("status", "open"),
        "createdAt": at, "updatedAt": at, "rectificationEvidence": [],
        "closeoutEvidence": [], "comments": [], "issueHistory": [],
        "inspectionHistory": [], "auditEvents": [], "sync": "synced",
        **payload,
    }
    item["auditEvents"] = [{"at": at, "action": f"Created ({code})" + (" via Voice-to-Note" if payload.get("voiceTranscript") else ""), "by": payload.get("createdBy")}]
    STATE["items"].insert(0, item)
    return item


ALLOWED_ACTIONS_BY_STATUS = {
    "open": {"issue", "comment", "reopen"},
    "issued": {"in-progress", "ready", "rectification", "issue", "comment", "reopen"},
    "in_progress": {"ready", "rectification", "issue", "comment", "reopen"},
    "ready_for_review": {"inspect", "reject", "comment", "reopen"},
    "under_inspection": {"close", "reject", "comment", "reopen"},
    "rejected": {"issue", "in-progress", "rectification", "comment", "reopen"},
    "closed": {"reopen", "comment"},
    "complete": {"reopen", "comment"},
}


def apply_action(item: dict[str, Any], action: str, body: dict[str, Any]) -> None:
    body = copy.deepcopy(body)

    current_status = item.get("status", "open")
    allowed = ALLOWED_ACTIONS_BY_STATUS.get(current_status, {"comment"})
    if action not in allowed:
        raise ValueError(f"cannot perform '{action}' while item is {current_status.replace('_', ' ')}")

    if body.get("photo"):
        body["photo"] = maybe_upload_photo(
            body.get("photo"),
            folder=f"items/{item.get('id', 'unknown')}/{action}",
        )

    by = body.get("by") or STATE["settings"].get("preparedBy") or "Site Manager"
    at = now_iso()
    if action == "issue":
        target = body.get("to") or item.get("subcontractor")
        if not target or not item.get("trade"):
            raise ValueError("issuing requires a trade and subcontractor")
        reissue = bool(body.get("reissue"))
        item.update(status="issued", subcontractor=target)
        item.setdefault("issuedAt", at)
        item.setdefault("issueHistory", []).append({"at": at, "to": target, "by": by, "note": body.get("note"), "reissue": reissue})
        if not reissue: item.pop("rejectionReason", None)
        audit(item, f"{'Re-issued' if reissue else 'Issued'} to {target}", by, body.get("note"))
    elif action == "in-progress":
        item["status"] = "in_progress"; item.setdefault("inProgressAt", at); audit(item, "Marked in progress", by)
    elif action == "ready":
        item.update(status="ready_for_review", readyForReviewAt=at); audit(item, "Marked ready for review", by, body.get("note"))
    elif action == "inspect":
        item.update(status="under_inspection", underInspectionAt=at)
        item.setdefault("inspectionHistory", []).append({"at": at, "by": by, "action": "started"}); audit(item, "Inspection started", by)
    elif action == "reject":
        reason = str(body.get("reason", "")).strip()
        if not reason: raise ValueError("a rejection reason is required")
        item.update(status="rejected", rejectionReason=reason)
        item.setdefault("inspectionHistory", []).append({"at": at, "by": by, "action": "rejected", "reason": reason}); audit(item, "Rejected on inspection", by, reason)
    elif action == "rectification":
        if not body.get("photo") and not str(body.get("comment", "")).strip():
            raise ValueError("attach a photo or add a comment")
        item.setdefault("rectificationEvidence", []).append({"id": new_id(), "at": at, "photo": body.get("photo"), "photoMeta": body.get("photoMeta"), "comment": body.get("comment"), "by": by})
        if item["status"] == "issued": item.update(status="in_progress", inProgressAt=at)
        audit(item, "Rectification evidence added", by, body.get("comment"))
        if body.get("advanceToReady"):
            item.update(status="ready_for_review", readyForReviewAt=at); audit(item, "Marked ready for review", by)
    elif action == "close":
        if not body.get("confirmed"):
            raise ValueError("closeout confirmation is required")
        if item["type"] != "incomplete" and not body.get("photo"):
            raise ValueError("a closeout photo is required")
        item["status"] = "complete" if item["type"] == "incomplete" else "closed"
        item["closedAt"] = at
        if body.get("photo") or body.get("note"):
            item.setdefault("closeoutEvidence", []).append({"id": new_id(), "at": at, "photo": body.get("photo"), "photoMeta": body.get("photoMeta"), "by": by, "role": body.get("role", "Site Manager"), "note": body.get("note"), "confirmation": "I confirm the work is complete and acceptable." if body.get("confirmed") else None})
        if item.get("inspectionHistory") is not None and body.get("accepted", True):
            item["inspectionHistory"].append({"at": at, "by": by, "action": "accepted"})
        audit(item, "Closed with evidence" if item["type"] != "incomplete" else "Completed", by)
    elif action == "reopen":
        reason = str(body.get("reason", "")).strip()
        if not reason: raise ValueError("a reopen reason is required")
        item.update(status="in_progress", inProgressAt=at); item.pop("closedAt", None); audit(item, "Reopened", by, reason)
    elif action == "comment":
        text = str(body.get("text", "")).strip()
        if not text: raise ValueError("comment text is required")
        item.setdefault("comments", []).append({"id": new_id(), "at": at, "text": text, "by": by}); audit(item, "Comment added", by, text)
    else:
        raise ValueError("unknown action")

def is_overdue(item: dict[str, Any]) -> bool:
    return item.get("status") not in CLOSED and item.get("dueDate", "9999") < day_iso()


def report_items(kind: str) -> list[dict[str, Any]]:
    active = STATE["settings"]["activeProject"]
    items = [copy.deepcopy(item) for item in STATE["items"] if item.get("project") == active]
    if kind == "open": return [i for i in items if i["status"] not in CLOSED]
    if kind == "overdue": return [i for i in items if is_overdue(i)]
    if kind == "client": return [i for i in items if i["type"] == "client"]
    if kind == "incomplete": return [i for i in items if i["type"] == "incomplete"]
    if kind == "subcontractor": return sorted(items, key=lambda i: i.get("subcontractor", ""))
    if kind == "handover": return sorted(items, key=lambda i: (i["status"] not in CLOSED, i["updatedAt"]), reverse=False)
    raise ValueError("unknown report type")


def report_html(kind: str) -> str:
    titles = {
        "open": "Open Items",
        "overdue": "Overdue Items",
        "handover": "Closed / Handover Evidence",
        "subcontractor": "Subcontractor",
        "client": "Client Defects",
        "incomplete": "Incomplete Works",
    }
    items = report_items(kind)
    settings = STATE["settings"]

    def esc(value: Any) -> str:
        return html.escape(str(value or "-"))

    def photo_source(value: Any) -> str:
        source = str(value or "")
        if not source:
            return ""
        if source.startswith("seed://"):
            label = unquote(source.split("/", 3)[-1])
            svg = f'''<svg xmlns="http://www.w3.org/2000/svg" width="900" height="600" viewBox="0 0 900 600"><rect width="900" height="600" fill="#E9EDF0"/><path d="M0 480L210 280l140 140 130-120 300 300H0z" fill="#B9C0C8"/><circle cx="700" cy="150" r="58" fill="#20C55E"/><text x="450" y="535" text-anchor="middle" font-family="Arial,sans-serif" font-size="34" font-weight="700" fill="#121619">{html.escape(label)}</text></svg>'''
            return "data:image/svg+xml;base64," + base64.b64encode(svg.encode()).decode()
        return source

    def photo_caption(label: str, meta: Any) -> str:
        detail = ""
        if isinstance(meta, dict) and meta.get("latitude") is not None:
            detail = f"<span>Geo-tag {float(meta['latitude']):.5f}, {float(meta.get('longitude', 0)):.5f}"
            if meta.get("accuracy"):
                detail += f" ±{round(float(meta['accuracy']))}m"
            detail += "</span>"
        return f"<b>{esc(label)}</b>{detail}"

    rows: list[str] = []
    for item in items:
        original_count = len(item.get("originalPhotos", []))
        rectification_count = len(item.get("rectificationEvidence", []))
        closeout_count = len(item.get("closeoutEvidence", []))
        location = " / ".join(filter(None, [item.get("building"), item.get("level"), item.get("unit"), item.get("room")]))
        status = re.sub(r"[^a-z_-]", "", str(item.get("status", "open")))
        photos: list[tuple[str, str, Any]] = []
        original_meta = item.get("originalPhotoMeta", [])
        for index, photo in enumerate(item.get("originalPhotos", [])):
            photos.append((f"Original issue {index + 1}", photo_source(photo), original_meta[index] if index < len(original_meta) else None))
        for index, evidence in enumerate(item.get("rectificationEvidence", [])):
            if evidence.get("photo"):
                photos.append((f"Rectification {index + 1}", photo_source(evidence["photo"]), evidence.get("photoMeta")))
        for index, evidence in enumerate(item.get("closeoutEvidence", [])):
            if evidence.get("photo"):
                photos.append((f"Closeout {index + 1}", photo_source(evidence["photo"]), evidence.get("photoMeta")))
        gallery = "".join(
            f'<figure class="photo"><img src="{html.escape(source, quote=True)}" alt="{esc(label)}"><figcaption>{photo_caption(label, meta)}</figcaption></figure>'
            for label, source, meta in photos if source
        )
        rows.append(
            f"""
            <article class="item item--{status}">
              <header><div><b class="code">{esc(item['code'])}</b><small>{esc(TYPE_LABEL[item['type']])}</small></div><span class="status {status}">{esc(STATUS_LABEL.get(item['status'], item['status']))}</span></header>
              <div class="register"><span>{esc(location)}</span><span>{esc(item.get('trade'))}</span><span>{esc(item.get('subcontractor'))}</span></div>
              <p class="description">{esc(item['description'])}</p>
              <div class="evidence"><div><b>Original issue</b><span>{original_count} photo{'' if original_count == 1 else 's'}</span></div><div><b>Rectification</b><span>{rectification_count} record{'' if rectification_count == 1 else 's'}</span></div><div><b>Closeout</b><span>{closeout_count} record{'' if closeout_count == 1 else 's'}</span></div></div>
              {f'<div class="photo-grid">{gallery}</div>' if gallery else ''}
              <footer><span>Evidence chain: {original_count} / {rectification_count} / {closeout_count}</span><span class="due">Due {esc(item.get('dueDate'))}</span></footer>
            </article>
            """
        )

    generated = datetime.now().strftime("%d %b %Y %H:%M")
    return f"""<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{esc(titles[kind])}</title>
<style>
@import url('https://fonts.googleapis.com/css2?family=Archivo:wght@500;600;700;800&family=Inter:wght@400;500;600;700&display=swap');
*{{box-sizing:border-box;-webkit-print-color-adjust:exact;print-color-adjust:exact}}body{{margin:0;background:#F3F4F6;color:#121619;font:14px Inter,system-ui,sans-serif}}.shell{{max-width:1080px;margin:24px auto;background:#fff;border:1px solid #DDE1E5;padding:24px}}.brand{{display:flex;justify-content:space-between;gap:20px;align-items:start;border-bottom:4px solid #20C55E;padding-bottom:16px}}.brand img{{width:230px;max-width:55%;height:auto}}.meta{{text-align:right;color:#6B7280;line-height:1.55}}h1,h2,h3,.code,.status,.stat b,.stat span,.evidence b,button,a{{font-family:Archivo,system-ui,sans-serif}}h1{{font-size:30px;line-height:1;margin:22px 0 5px}}.tagline{{color:#6B7280;font-weight:600}}.actions{{display:flex;gap:8px;margin:16px 0}}button,a.back{{border:1px solid #121619;border-radius:7px;background:#fff;color:#121619;padding:10px 13px;text-decoration:none;font-weight:700;cursor:pointer}}button{{background:#18A94F;border-color:#18A94F}}.summary{{display:grid;grid-template-columns:repeat(4,1fr);gap:9px;margin:18px 0 22px}}.stat{{border:1px solid #DDE1E5;border-left:4px solid #121619;background:#F8F9FA;padding:12px}}.stat:nth-child(2){{border-left-color:#20C55E}}.stat:nth-child(3){{border-left-color:#B42318}}.stat:nth-child(4){{border-left-color:#6B7280}}.stat b{{display:block;font-size:28px}}.stat span{{color:#6B7280;font-size:9px;font-weight:700;letter-spacing:.08em;text-transform:uppercase}}.item{{border:1px solid #DDE1E5;border-left:5px solid #6B7280;padding:13px;margin:10px 0;break-inside:avoid}}.item--closed,.item--complete{{border-left-color:#20C55E}}.item--rejected{{border-left-color:#B42318}}.item header,.item footer{{display:flex;justify-content:space-between;gap:12px;align-items:start}}.code{{display:block;font-size:16px;line-height:1.15;font-weight:800}}small{{display:block;color:#6B7280;margin-top:2px}}.status{{border:1px solid #B9C0C8;background:#F8F9FA;padding:4px 7px;font-size:9px;font-weight:700;text-transform:uppercase}}.status.closed,.status.complete{{border-color:#20C55E;background:#E1F7E9;color:#0C7733}}.status.rejected{{border-color:#B42318;background:#FEE4E2;color:#B42318}}.register{{display:grid;grid-template-columns:1.4fr .8fr 1fr;gap:7px;margin-top:8px}}.register span{{border:1px solid #DDE1E5;background:#F8F9FA;color:#52606D;padding:6px;font-size:11px;font-weight:600}}.description{{line-height:1.45}}.evidence{{display:grid;grid-template-columns:repeat(3,1fr);gap:7px;margin:10px 0}}.evidence div{{display:grid;gap:3px;border:1px solid #DDE1E5;border-top:3px solid #6B7280;background:#F8F9FA;padding:8px}}.evidence div:last-child{{border-top-color:#20C55E}}.evidence b{{font-size:9px;letter-spacing:.06em;text-transform:uppercase}}.evidence span,footer{{color:#6B7280;font-size:10px}}.photo-grid{{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:9px;margin:12px 0}}.photo{{margin:0;border:1px solid #DDE1E5;background:#F8F9FA;padding:6px;break-inside:avoid}}.photo img{{display:block;width:100%;height:155px;object-fit:cover;background:#E9EDF0}}.photo figcaption{{display:grid;gap:2px;padding-top:5px;color:#52606D;font-size:9px;line-height:1.35}}.photo figcaption b{{font-family:Archivo,system-ui,sans-serif;color:#121619;font-size:10px}}.due{{margin-left:auto}}.empty{{border:1px dashed #B9C0C8;background:#F8F9FA;padding:18px;color:#6B7280}}.footer{{margin-top:24px;padding-top:12px;border-top:1px solid #DDE1E5;text-align:center;color:#6B7280;font-size:9px;letter-spacing:.07em;text-transform:uppercase}}
@media(max-width:700px){{.shell{{margin:0;padding:15px}}.brand{{display:block}}.meta{{text-align:left;margin-top:10px}}.summary{{grid-template-columns:repeat(2,1fr)}}.register,.evidence{{grid-template-columns:1fr}}.photo-grid{{grid-template-columns:repeat(2,minmax(0,1fr))}}.photo img{{height:130px}}h1{{font-size:26px}}}}@media print{{body{{background:#fff}}.shell{{max-width:none;margin:0;border:0;padding:10mm}}.actions{{display:none}}.photo-grid{{grid-template-columns:repeat(3,minmax(0,1fr))}}.photo img{{height:42mm}}}}
</style></head><body><main class="shell"><header class="brand"><div><img src="/assets/banner.png" alt="CleanRun IQ"><div class="tagline">Smarter Field. Cleaner Builds.</div></div><div class="meta"><strong>{esc(settings['company'])}</strong><br>{esc(settings['activeProject'])}<br>Generated {esc(generated)}</div></header><h1>{esc(titles[kind])} Report</h1><div class="tagline">Evidence-first field capture, assignment and closeout register.</div><div class="actions"><a class="back" href="/">Back to app</a><button type="button" onclick="window.print()">Print / Save PDF</button></div><section class="summary"><div class="stat"><b>{len(items)}</b><span>Total items</span></div><div class="stat"><b>{sum(i['status'] in CLOSED for i in items)}</b><span>Closed / Complete</span></div><div class="stat"><b>{sum(is_overdue(i) for i in items)}</b><span>Overdue</span></div><div class="stat"><b>{sum(i['type']=='client' for i in items)}</b><span>Client defects</span></div></section>{''.join(rows) or '<div class="empty">No items match this report.</div>'}<footer class="footer">CleanRun IQ - Smarter Field. Cleaner Builds. - Original Issue / Rectification / Supervisor Closeout</footer></main></body></html>"""


class Handler(BaseHTTPRequestHandler):
    server_version = "CleanRunIQ/1.0"

    def log_message(self, fmt: str, *args: Any) -> None:
        print(f"[{self.log_date_time_string()}] {fmt % args}")

    def send_bytes(self, body: bytes, content_type: str, status: int = 200) -> None:
        self.send_response(status); self.send_header("Content-Type", content_type); self.send_header("Content-Length", str(len(body))); self.send_header("Cache-Control", "no-store"); self.end_headers(); self.wfile.write(body)

    def send_json(self, value: Any, status: int = 200) -> None:
        self.send_bytes(json.dumps(value, ensure_ascii=False).encode(), "application/json; charset=utf-8", status)

    def body(self) -> dict[str, Any]:
        length = int(self.headers.get("Content-Length", 0))
        max_bytes = int(os.environ.get("CLEANRUN_MAX_REQUEST_BYTES", "50000000"))
        if length > max_bytes: raise ValueError("request is too large")
        return json.loads(self.rfile.read(length) or b"{}")

    def do_GET(self) -> None:  # noqa: N802
        path = urlparse(self.path).path
        try:
            if path in {"/", "/index.html"}:
                self.send_bytes(INDEX_FILE.read_bytes() if INDEX_FILE.exists() else EMBEDDED_INDEX, "text/html; charset=utf-8")
            elif path in {"/assets/banner.png", "/assets/icon-mark.png"}:
                self.send_bytes((ROOT / path.lstrip("/")).read_bytes() if (ROOT / path.lstrip("/")).exists() else EMBEDDED_ASSETS[path], "image/png")
            elif path == "/assets/chevrons.svg":
                self.send_bytes((ROOT / path.lstrip("/")).read_bytes(), "image/svg+xml; charset=utf-8")
            elif path in {"/assets/enhancements.css", "/assets/enhancements.js"}:
                content_type = "text/css; charset=utf-8" if path.endswith(".css") else "text/javascript; charset=utf-8"
                self.send_bytes((ROOT / path.lstrip("/")).read_bytes(), content_type)
            elif path in {"/service-worker.js", "/manifest.webmanifest"}:
                content_type = "text/javascript; charset=utf-8" if path.endswith(".js") else "application/manifest+json; charset=utf-8"
                self.send_bytes((ROOT / path.lstrip("/")).read_bytes(), content_type)
            elif path == "/api/state": self.send_json(STATE)
            elif path.startswith("/api/items/"): self.send_json(get_item(unquote(path.split("/")[-1])))
            elif path.startswith("/api/reports/"):
                self.send_bytes(report_html(path.split("/")[-1]).encode(), "text/html; charset=utf-8")
            elif path == "/api/health": self.send_json({"ok": True})
            elif path == "/api/storage-status":
                self.send_json({
                    "ok": True,
                    "storageBackend": os.environ.get("CLEANRUN_STORAGE", "local"),
                    "usingSupabaseStorage": use_supabase_storage(),
                    "storageBucket": os.environ.get("CLEANRUN_STORAGE_BUCKET", "cleanrun-evidence"),
                    "stateBackend": os.environ.get("CLEANRUN_STATE_BACKEND", "local"),
                    "usingSupabaseState": use_supabase_state(),
                    "stateTable": os.environ.get("CLEANRUN_STATE_TABLE", "cleanrun_state"),
                    "stateId": os.environ.get("CLEANRUN_STATE_ID", "production"),
                    "hasSupabaseUrl": bool(os.environ.get("SUPABASE_URL")),
                    "hasServiceRoleKey": bool(os.environ.get("SUPABASE_SERVICE_ROLE_KEY") or os.environ.get("SUPABASE_KEY")),
                    "maxImageBytes": int(os.environ.get("CLEANRUN_MAX_IMAGE_BYTES", "8000000")),
                    "maxRequestBytes": int(os.environ.get("CLEANRUN_MAX_REQUEST_BYTES", "50000000")),
                })
            else: self.send_json({"error": "Not found"}, 404)
        except (KeyError, ValueError) as exc: self.send_json({"error": str(exc)}, 404)
        except Exception as exc: self.send_json({"error": f"Server error: {exc}"}, 500)

    def do_POST(self) -> None:  # noqa: N802
        path = urlparse(self.path).path
        try:
            body = self.body()
            with LOCK:
                if path == "/api/items": result = create_item(body)
                elif path == "/api/parse": result = parse_transcript(str(body.get("transcript", "")))
                elif path == "/api/reset":
                    global STATE
                    STATE = default_state(); result = STATE
                elif path == "/api/settings":
                    allowed = {"company", "preparedBy", "activeProject", "projects", "projectConfigs", "subcontractors", "subProfiles", "theme"}
                    STATE["settings"].update({k: v for k, v in body.items() if k in allowed}); result = STATE["settings"]
                elif path == "/api/plans":
                    body = copy.deepcopy(body)
                    if body.get("image"):
                        body["image"] = maybe_upload_plan_asset(
                            body.get("image"),
                            folder=f"plans/{body.get('project') or STATE['settings'].get('activeProject', 'unknown')}",
                        )
                    result = {"id": new_id(), "pins": [], "createdAt": now_iso(), **body}; STATE["plans"].insert(0, result)
                elif re.fullmatch(r"/api/plans/[^/]+/pins", path):
                    plan_id = path.split("/")[3]; plan = next(p for p in STATE["plans"] if p["id"] == plan_id)
                    result = {"id": new_id(), **body}; plan["pins"].append(result)
                elif re.fullmatch(r"/api/items/[^/]+/actions/[^/]+", path):
                    parts = path.split("/"); result = get_item(unquote(parts[3])); apply_action(result, parts[5], body)
                else: self.send_json({"error": "Not found"}, 404); return
                save_state(STATE)
            self.send_json(result, 201 if path in {"/api/items", "/api/plans"} else 200)
        except StopIteration: self.send_json({"error": "Plan not found"}, 404)
        except (KeyError, ValueError, json.JSONDecodeError) as exc: self.send_json({"error": str(exc)}, 400)
        except Exception as exc: self.send_json({"error": f"Server error: {exc}"}, 500)

    def do_PATCH(self) -> None:  # noqa: N802
        path = urlparse(self.path).path
        try:
            body = self.body()
            with LOCK:
                match = re.fullmatch(r"/api/items/([^/]+)", path)
                pin_match = re.fullmatch(r"/api/plans/([^/]+)/pins/([^/]+)", path)
                if match:
                    result = get_item(unquote(match.group(1)))
                    allowed = {"type", "project", "building", "level", "unit", "room", "trade", "subcontractor", "priority", "dueDate", "description", "raisedBy", "originalPhotos", "originalPhotoMeta"}
                    previous_photos = len(result.get("originalPhotos", []))
                    update = {k: v for k, v in body.items() if k in allowed}
                    if "originalPhotos" in update:
                        update["originalPhotos"] = upload_photo_list(
                            update.get("originalPhotos", []),
                            folder=f"items/{result.get('id', 'unknown')}/original",
                        )
                    result.update(update)
                    added_photos = max(0, len(result.get("originalPhotos", [])) - previous_photos)
                    audit(result, f"Item details edited{f' · {added_photos} retrospective photo(s) added' if added_photos else ''}", body.get("by"))
                elif pin_match:
                    plan = next(p for p in STATE["plans"] if p["id"] == pin_match.group(1)); result = next(p for p in plan["pins"] if p["id"] == pin_match.group(2)); result.update(body)
                else: self.send_json({"error": "Not found"}, 404); return
                save_state(STATE)
            self.send_json(result)
        except (KeyError, ValueError, StopIteration) as exc: self.send_json({"error": str(exc) or "Not found"}, 404)

    def do_DELETE(self) -> None:  # noqa: N802
        path = urlparse(self.path).path
        try:
            with LOCK:
                plan_match = re.fullmatch(r"/api/plans/([^/]+)", path)
                pin_match = re.fullmatch(r"/api/plans/([^/]+)/pins/([^/]+)", path)
                if pin_match:
                    plan = next(p for p in STATE["plans"] if p["id"] == pin_match.group(1)); plan["pins"] = [p for p in plan["pins"] if p["id"] != pin_match.group(2)]
                elif plan_match: STATE["plans"] = [p for p in STATE["plans"] if p["id"] != plan_match.group(1)]
                else: self.send_json({"error": "Not found"}, 404); return
                save_state(STATE)
            self.send_json({"ok": True})
        except StopIteration: self.send_json({"error": "Not found"}, 404)


def main() -> None:
    # Render injects PORT and requires the service to listen on all interfaces.
    host = os.environ.get("HOST", "0.0.0.0")
    port = int(os.environ.get("PORT", "8000"))
    server = ThreadingHTTPServer((host, port), Handler)
    display_host = "127.0.0.1" if host == "0.0.0.0" else host
    url = f"http://{display_host}:{port}"
    print(f"CleanRun IQ running at {url} (Ctrl+C to stop)")
    if os.environ.get("CLEANRUN_OPEN_BROWSER") == "1": threading.Timer(.5, webbrowser.open, args=(url,)).start()
    try: server.serve_forever()
    except KeyboardInterrupt: print("\nStopped.")
    finally: server.server_close()


if __name__ == "__main__":
    main()
